// Função utilitária para integrar os tokens Strong na estrutura do versículo
export const integrateStrongs = (verses: Verse[]): Verse[] => {
  return verses.map(v => {
    const seedTokens = (STRONG_TOKENS as any)[v.id];
    if (!seedTokens || !Array.isArray(seedTokens)) return v;

    // Detectar se o versículo é hebraico (para usar lógica de maqaf e normalização específica)
    const isHebrew = isHebrewWord(v.text);

    // 1. Normalizar e expandir os tokens do seed
    const normalizedSeed: any[] = [];
    seedTokens.forEach((t: any) => {
      const surface = t.surface || t.t || t.text || '';
      
      if (isHebrew) {
        // Lógica para Hebraico (maqaf)
        const parts = surface.split('־');
        if (parts.length > 1) {
          parts.forEach((p: string, idx: number) => {
            normalizedSeed.push({
              surface: p,
              normalized: normalizeHebrew(p),
              strong: idx === parts.length - 1 ? t.strong : null,
              lemma: idx === parts.length - 1 ? t.lemma : null,
              morph: idx === parts.length - 1 ? t.morph : null,
            });
          });
        } else {
          normalizedSeed.push({
            surface: surface,
            normalized: t.normalized || normalizeHebrew(surface),
            strong: t.strong,
            lemma: t.lemma,
            morph: t.morph,
            transliteration: t.transliteration,
            definition: t.definition
          });
        }
      } else {
        // Lógica para Português/Outros
        normalizedSeed.push({
          surface: surface,
          normalized: surface.normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^\w]/g, '').toLowerCase(),
          strong: t.strong,
          lemma: t.lemma,
          morph: t.morph,
          transliteration: t.transliteration,
          definition: t.definition
        });
      }
    });

    // 2. Tokenizar o texto original do versículo
    const verseTokens = isHebrew 
      ? tokenizeHebrew(v.text) 
      : v.text.split(/([\s,.;:!?()]+)/).filter(p => p.length > 0);
    
    // 3. Casar palavras do versículo com tokens do seed
    let seedIdx = 0;
    const finalWords = verseTokens.map(token => {
      const isWord = isHebrew ? isHebrewWord(token) : /[a-zA-Z\u00C0-\u00FF]/.test(token);
      
      if (!isWord) {
        return {
          text: token,
          strong: [],
          lemma: [],
          morph: [],
          transliteration: [],
          definition: []
        };
      }

      const normWord = isHebrew 
        ? normalizeHebrew(token) 
        : token.normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^\w]/g, '').toLowerCase();
      
      // Busca o melhor match no seed
      let match = null;
      for (let i = 0; i < 5; i++) {
        const potentialMatch = normalizedSeed[seedIdx + i];
        if (potentialMatch && potentialMatch.normalized === normWord) {
          match = potentialMatch;
          seedIdx += i + 1;
          break;
        }
      }

      if (match) {
        return {
          text: token,
          strong: Array.isArray(match.strong) ? match.strong : (match.strong ? [match.strong] : []),
          lemma: Array.isArray(match.lemma) ? match.lemma : (match.lemma ? [match.lemma] : []),
          morph: Array.isArray(match.morph) ? match.morph : (match.morph ? [match.morph] : []),
          transliteration: Array.isArray(match.transliteration) ? match.transliteration : (match.transliteration ? [match.transliteration] : []),
          definition: Array.isArray(match.definition) ? match.definition : (match.definition ? [match.definition] : [])
        };
      }

      // Sem match, mantém o texto original sem Strong
      return {
        text: token,
        strong: [],
        lemma: [],
        morph: [],
        transliteration: [],
        definition: []
      };
    });

    return {
      ...v,
      words: finalWords
    };
  });
};

